class Student {
    constructor(name, rollNo, marks) {
        this.name = name;
        this.rollNo = rollNo;
        this.marks = marks;
        this.grade = this.calculateGrade();
    }

    calculateGrade() {
        if(this.marks >= 90) return 'A+';
        if(this.marks >= 80) return 'A';
        if(this.marks >= 70) return 'B';
        if(this.marks >= 60) return 'C';
        if(this.marks >= 50) return 'D';
        return 'F';
    }
}

class StudentManagementSystem {
    constructor() {
        this.students = [];
    }

    addStudent(name, rollNo, marks) {
        const existing = this.students.find(s => s.rollNo === rollNo);
        if(existing) {
            console.log('Student with this roll number already exists!');
            return false;
        }
        const student = new Student(name, rollNo, marks);
        this.students.push(student);
        console.log(`Student ${name} added successfully!`);
        return true;
    }

    displayAll() {
        if(this.students.length === 0) {
            console.log('No students found!');
            return;
        }
        console.log('\n' + '='.repeat(60));
        console.log('Roll No | Name | Marks | Grade');
        console.log('='.repeat(60));
        this.students.forEach(s => {
            console.log(`${s.rollNo} | ${s.name} | ${s.marks} | ${s.grade}`);
        });
    }

    findTopper() {
        const topper = this.students.reduce((max, s) => 
            s.marks > max.marks ? s : max
        );
        console.log(`\nTopper: ${topper.name} (Roll: ${topper.rollNo}) with ${topper.marks} marks (${topper.grade})`);
        return topper;
    }

    getAverageMarks() {
        const total = this.students.reduce((sum, s) => sum + s.marks, 0);
        const average = total / this.students.length;
        console.log(`\nAverage Marks: ${average.toFixed(2)}`);
        return average;
    }

    filterByGrade(grade) {
        const filtered = this.students.filter(s => s.grade === grade);
        console.log(`\nStudents with grade ${grade}:`);
        filtered.forEach(s => console.log(`${s.name} (${s.rollNo})`));
        return filtered;
    }

    getStudentsAboveThreshold(threshold) {
        return this.students.filter(s => s.marks > threshold);
    }

    sortByMarks(descending = true) {
        const sorted = [...this.students].sort((a, b) => 
            descending ? b.marks - a.marks : a.marks - b.marks
        );
        console.log('\nStudents sorted by marks:');
        sorted.forEach(s => console.log(`${s.name}: ${s.marks} marks`));
        return sorted;
    }
}

// Demonstration
const sms = new StudentManagementSystem();
sms.addStudent('Alice Johnson', 101, 85);
sms.addStudent('Bob Smith', 102, 92);
sms.addStudent('Charlie Brown', 103, 78);
sms.addStudent('Diana Prince', 104, 95);
sms.addStudent('Ethan Hunt', 105, 67);

sms.displayAll();
sms.findTopper();
sms.getAverageMarks();
sms.filterByGrade('A');
sms.sortByMarks(true);

const topStudents = sms.getStudentsAboveThreshold(80);
console.log('\nStudents above 80 marks:', topStudents.map(s => s.name));
```

