<body>
    <div class="container">
        <h1>📝 Todo List</h1>
        <div class="input-section">
            <input type="text" id="taskInput" placeholder="Enter a new task...">
            <button onclick="addTask()">Add Task</button>
        </div>

        <div class="filter-buttons">
            <button class="filter-btn active" onclick="filterTasks('all')">All</button>
            <button class="filter-btn" onclick="filterTasks('pending')">Pending</button>
            <button class="filter-btn" onclick="filterTasks('completed')">Completed</button>
        </div>

        <div id="todoList"></div>

        <div class="stats">
            <span id="pendingCount">0</span> tasks pending
        </div>

        <button class="clear-completed" onclick="clearCompleted()">Clear Completed</button>
    </div>

    <script>
        let todos = [];
        let currentFilter = 'all';

        // Load from localStorage
        function loadTodos() {
            const saved = localStorage.getItem('todos');
            if(saved) {
                todos = JSON.parse(saved);
            }
            renderTodos();
        }

        // Save to localStorage
        function saveTodos() {
            localStorage.setItem('todos', JSON.stringify(todos));
        }

        // Add new task
        function addTask() {
            const input = document.getElementById('taskInput');
            const text = input.value.trim();
            if(text === '') {
                alert('Please enter a task!');
                return;
            }

            todos.push({
                id: Date.now(),
                text: text,
                completed: false
            });

            input.value = '';
            saveTodos();
            renderTodos();
        }

        // Toggle task completion
        function toggleTask(id) {
            const todo = todos.find(t => t.id === id);
            if(todo) {
                todo.completed = !todo.completed;
                saveTodos();
                renderTodos();
            }
        }

        // Delete task
        function deleteTask(id) {
            todos = todos.filter(t => t.id !== id);
            saveTodos();
            renderTodos();
        }

        // Filter tasks
        function filterTasks(filter) {
            currentFilter = filter;
            document.querySelectorAll('.filter-btn').forEach(btn => {
                btn.classList.remove('active');
            });
            event.target.classList.add('active');
            renderTodos();
        }

        // Clear completed tasks
        function clearCompleted() {
            todos = todos.filter(t => !t.completed);
            saveTodos();
            renderTodos();
        }

        // Render todos based on filter
        function renderTodos() {
            const todoList = document.getElementById('todoList');
            let filteredTodos = todos;

            if(currentFilter === 'pending') {
                filteredTodos = todos.filter(t => !t.completed);
            } else if(currentFilter === 'completed') {
                filteredTodos = todos.filter(t => t.completed);
            }

            todoList.innerHTML = '';
            filteredTodos.forEach(todo => {
                const todoDiv = document.createElement('div');
                todoDiv.className = `todo-item ${todo.completed ? 'completed' : ''}`;

                todoDiv.innerHTML = `
                    <span class="todo-text" onclick="toggleTask(${todo.id})">${todo.text}</span>
                    <button class="delete-btn" onclick="deleteTask(${todo.id})">Delete</button>
                `;

                todoList.appendChild(todoDiv);
            });

            const pendingCount = todos.filter(t => !t.completed).length;
            document.getElementById('pendingCount').textContent = pendingCount;
        }

        // Initialize
        loadTodos();
    </script>
</body>
</html>
