// Employee Management System

class Employee {
    constructor(id, name, department, position, salary, joinDate, performanceScore = 3) {
        this.id = id;
        this.name = name;
        this.department = department;
        this.position = position;
        this.salary = salary;
        this.joinDate = new Date(joinDate);
        this.performanceScore = performanceScore;
        this.createdAt = new Date();
    }

    // Calculate bonus based on performance and salary
    calculateBonus() {
        const bonusRates = {
            5: 0.20, // 20% bonus for excellent
            4: 0.15, // 15% bonus for good
            3: 0.10, // 10% bonus for average
            2: 0.05, // 5% bonus for below average
            1: 0.00  // No bonus for poor
        };
        const rate = bonusRates[this.performanceScore] || 0;
        return this.salary * rate;
    }

    // Calculate years of experience
    getExperience() {
        const today = new Date();
        const years = today.getFullYear() - this.joinDate.getFullYear();
        const months = today.getMonth() - this.joinDate.getMonth();
        return years + (months / 12);
    }

    // Update performance score
    updatePerformance(score) {
        if(score >= 1 && score <= 5) {
            this.performanceScore = score;
            return true;
        }
        return false;
    }

    // Get performance category
    getPerformanceCategory() {
        const categories = {
            5: 'Excellent',
            4: 'Good',
            3: 'Average',
            2: 'Below Average',
            1: 'Poor'
        };
        return categories[this.performanceScore] || 'Not Rated';
    }

    // Employee to JSON
    toJSON() {
        return {
            id: this.id,
            name: this.name,
            department: this.department,
            position: this.position,
            salary: this.salary,
            joinDate: this.joinDate.toISOString(),
            performanceScore: this.performanceScore,
            createdAt: this.createdAt.toISOString()
        };
    }

    // Create employee from JSON
    static fromJSON(data) {
        const emp = new Employee(
            data.id, data.name, data.department, data.position,
            data.salary, data.joinDate, data.performanceScore
        );
        emp.createdAt = new Date(data.createdAt);
        return emp;
    }
}

class EmployeeManagementSystem {
    constructor() {
        this.employees = [];
        this.nextId = 1;
        this.departments = new Set();
        this.loadFromStorage();
    }

    // ========== Storage Methods ==========
    saveToStorage() {
        const data = {
            employees: this.employees.map(emp => emp.toJSON()),
            nextId: this.nextId,
            departments: Array.from(this.departments)
        };
        localStorage.setItem('employeeSystem', JSON.stringify(data));
    }

    loadFromStorage() {
        const saved = localStorage.getItem('employeeSystem');
        if(saved) {
            const data = JSON.parse(saved);
            this.employees = data.employees.map(emp => Employee.fromJSON(emp));
            this.nextId = data.nextId;
            this.departments = new Set(data.departments);
            this.updateDepartments();
        }
    }

    // ========== Employee CRUD Operations ==========
    addEmployee(name, department, position, salary, joinDate, performanceScore = 3) {
        if(!name || !department || !position || !salary) {
            throw new Error('All fields are required');
        }

        const employee = new Employee(
            this.nextId++, name, department, position, salary, joinDate, performanceScore
        );
        this.employees.push(employee);
        this.departments.add(department);
        this.saveToStorage();
        console.log(`✅ Employee ${name} added successfully with ID: ${employee.id}`);
        return employee;
    }

    updateEmployee(id, updates) {
        const employee = this.employees.find(emp => emp.id === id);
        if(!employee) {
            throw new Error(`Employee with ID ${id} not found`);
        }

        Object.keys(updates).forEach(key => {
            if(key in employee && key !== 'id' && key !== 'createdAt') {
                if(key === 'department') {
                    employee[key] = updates[key];
                    this.departments.add(updates[key]);
                } else if(key === 'performanceScore') {
                    employee.updatePerformance(updates[key]);
                } else {
                    employee[key] = updates[key];
                }
            }
        });

        this.saveToStorage();
        console.log(`✅ Employee ${employee.name} updated successfully`);
        return employee;
    }

    deleteEmployee(id) {
        const index = this.employees.findIndex(emp => emp.id === id);
        if(index === -1) {
            throw new Error(`Employee with ID ${id} not found`);
        }

        const removed = this.employees.splice(index, 1)[0];
        this.updateDepartments();
        this.saveToStorage();
        console.log(`✅ Employee ${removed.name} removed successfully`);
        return removed;
    }

    // ========== Filter and Search Methods ==========
    filterByDepartment(department) {
        return this.employees.filter(emp => 
            emp.department.toLowerCase() === department.toLowerCase()
        );
    }

    filterByPerformance(minScore, maxScore = 5) {
        return this.employees.filter(emp => 
            emp.performanceScore >= minScore && emp.performanceScore <= maxScore
        );
    }

    filterBySalaryRange(minSalary, maxSalary) {
        return this.employees.filter(emp => 
            emp.salary >= minSalary && emp.salary <= maxSalary
        );
    }

    searchEmployees(query) {
        const searchTerm = query.toLowerCase();
        return this.employees.filter(emp => 
            emp.name.toLowerCase().includes(searchTerm) ||
            emp.department.toLowerCase().includes(searchTerm) ||
            emp.position.toLowerCase().includes(searchTerm)
        );
    }

    // ========== Sorting Methods ==========
    sortBySalary(descending = true) {
        return [...this.employees].sort((a, b) => 
            descending ? b.salary - a.salary : a.salary - b.salary
        );
    }

    sortByJoinDate(newestFirst = true) {
        return [...this.employees].sort((a, b) => 
            newestFirst ? b.joinDate - a.joinDate : a.joinDate - b.joinDate
        );
    }

    sortByPerformance(descending = true) {
        return [...this.employees].sort((a, b) => 
            descending ? b.performanceScore - a.performanceScore : a.performanceScore - b.performanceScore
        );
    }

    // ========== Analysis Methods ==========
    getTopPerformers(limit = 3) {
        return this.sortByPerformance(true).slice(0, limit);
    }

    getDepartmentStats() {
        const stats = {};
        this.employees.forEach(emp => {
            if(!stats[emp.department]) {
                stats[emp.department] = {
                    count: 0,
                    totalSalary: 0,
                    avgSalary: 0,
                    totalBonus: 0,
                    employees: []
                };
            }
            stats[emp.department].count++;
            stats[emp.department].totalSalary += emp.salary;
            stats[emp.department].totalBonus += emp.calculateBonus();
            stats[emp.department].employees.push(emp.name);
            stats[emp.department].avgSalary = stats[emp.department].totalSalary / stats[emp.department].count;
        });
        return stats;
    }

    getPerformanceDistribution() {
        const distribution = { Excellent: 0, Good: 0, Average: 0, 'Below Average': 0, Poor: 0 };
        this.employees.forEach(emp => {
            const category = emp.getPerformanceCategory();
            distribution[category]++;
        });
        return distribution;
    }

    getSalaryStatistics() {
        const salaries = this.employees.map(emp => emp.salary);
        return {
            total: salaries.reduce((sum, s) => sum + s, 0),
            average: salaries.reduce((sum, s) => sum + s, 0) / this.employees.length,
            min: Math.min(...salaries),
            max: Math.max(...salaries),
            median: this.calculateMedian(salaries)
        };
    }

    calculateMedian(arr) {
        const sorted = [...arr].sort((a, b) => a - b);
        const mid = Math.floor(sorted.length / 2);
        return sorted.length % 2 === 0 ? (sorted[mid - 1] + sorted[mid]) / 2 : sorted[mid];
    }

    // ========== Bonus Calculation ==========
    calculateTotalBonus() {
        return this.employees.reduce((total, emp) => total + emp.calculateBonus(), 0);
    }

    calculateDepartmentBonus(department) {
        return this.filterByDepartment(department)
            .reduce((total, emp) => total + emp.calculateBonus(), 0);
    }

    // ========== Reporting Methods ==========
    generateFullReport() {
        console.log('\n' + '='.repeat(80));
        console.log('📊 EMPLOYEE MANAGEMENT SYSTEM REPORT');
